  'active'
) ON CONFLICT (tenant_id, key, locale, version) DO NOTHING;

INSERT INTO help_content (id, tenant_id, key, audience, locale, short_text, long_md, version, status)
VALUES (
  gen_random_uuid(),
  NULL,
  'admin.assessments.close.early',
  'admin',
  'en',
  'Sends auto-submit to every in-progress attempt. Cannot be undone — closes the schedule immediately.',
  $$## Close assessment early

Forces the assessment from `active` to `closed` immediately, regardless of
`closes_at`. Effects:

- Every in-progress attempt is auto-submitted with whatever answers exist.
- Pending invitations are revoked; their links return a "this assessment
  is closed" page if used.
- Notifications fire as if the schedule had ended naturally.

**You cannot reopen** a closed assessment whose `closes_at` has passed.
Re-opening before `closes_at` is allowed but rare — see
`assessment.reopen` (admin-only, audited).

Use this for: an emergency stop (compromised question content, vendor
incident). Do **not** use this to "give one candidate extra time" — that
is a per-attempt extension, not an assessment-level action.
$$,
  1,
  'active'
) ON CONFLICT (tenant_id, key, locale, version) DO NOTHING;

INSERT INTO help_content (id, tenant_id, key, audience, locale, short_text, long_md, version, status)
VALUES (
